// src/components/Dashboard.js
import React, { useEffect, useState } from "react";
import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
} from "chart.js";
import { Doughnut, Bar } from "react-chartjs-2";
import "./Dashboard.css";

ChartJS.register(ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title);

const Dashboard = () => {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const response = await fetch("/api/dashboard-stats");
        const data = await response.json();
        setStats(data);
      } catch (err) {
        console.error("Error fetching dashboard stats:", err);
      }
    };
    fetchStats();
  }, []);

  if (!stats) return <div className="loading">Loading dashboard data...</div>;

  const donutOptions = {
    cutout: "70%",
    plugins: {
      legend: { display: false },
      tooltip: { enabled: true },
    },
  };

  const getDonutData = (label, value, color) => ({
    labels: [label, ""],
    datasets: [
      {
        data: [value, 100 - value],
        backgroundColor: [color, "#e0e0e0"],
        borderWidth: 0,
      },
    ],
  });

  const occupiedVsFreeData = {
    labels: ["Occupied", "Free"],
    datasets: [
      {
        data: [stats.pieChart.occupied, stats.pieChart.free],
        backgroundColor: ["#f44336", "#4CAF50"],
        borderWidth: 0,
      },
    ],
  };

  const barData = {
    labels: Object.keys(stats.barChart),
    datasets: [
      {
        label: "Free Rooms",
        data: Object.values(stats.barChart),
        backgroundColor: [
          "#2196F3", "#8BC34A", "#FF9800", "#03A9F4", "#E91E63", "#FFC107"
        ],
        barThickness: 20,
      },
    ],
  };

  return (
    <div className="dashboard-container">
      <h2 className="page-title">Google Lighthouse - Classroom Dashboard</h2>

      <div className="dashboard-grid">
        <div className="card">
          <h4>Free vs Occupied</h4>
          <Doughnut data={occupiedVsFreeData} options={donutOptions} />
        </div>

        <div className="card">
          <h4>Projector Rooms</h4>
          <Doughnut data={getDonutData("Projectors", stats.resources.projectorRooms, "#FF9800")} options={donutOptions} />
          <div className="donut-number">{stats.resources.projectorRooms}</div>
        </div>

        <div className="card">
          <h4>Free Labs</h4>
          <Doughnut data={getDonutData("Labs", stats.resources.labs, "#9C27B0")} options={donutOptions} />
          <div className="donut-number">{stats.resources.labs}</div>
        </div>

        <div className="card">
          <h4>Free Classrooms</h4>
          <Doughnut data={getDonutData("Classrooms", stats.resources.classrooms, "#3F51B5")} options={donutOptions} />
          <div className="donut-number">{stats.resources.classrooms}</div>
        </div>

        <div className="card">
          <h4>Not Occupied</h4>
          <Doughnut data={getDonutData("Available", stats.resources.totalRooms - stats.pieChart.occupied, "#009688")} options={donutOptions} />
          <div className="donut-number">{stats.resources.totalRooms - stats.pieChart.occupied}</div>
        </div>

        <div className="card full-width">
          <h4>Free Rooms Per Weekday</h4>
          <Bar
            data={barData}
            options={{
              responsive: true,
              plugins: { legend: { display: false } },
              scales: { y: { beginAtZero: true } },
            }}
          />
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
